                new(DateTimeOffset.UtcNow.AddDays(-1), "Departed Chicago distribution center"),
            }),
        ["TRK-002"] = new ShipmentDetails(
            "TRK-002",
            "Delivered",
            "Seattle, WA",
            DateTimeOffset.UtcNow.AddDays(-1),
            new List<StatusUpdate>
            {
                new(DateTimeOffset.UtcNow.AddDays(-5), "Package picked up"),
                new(DateTimeOffset.UtcNow.AddDays(-4), "In transit to destination"),
                new(DateTimeOffset.UtcNow.AddDays(-2), "Out for delivery"),
