using System.Net.Http.Json;

namespace sv_074dd76458af4108a31c32dfa9d31302.Client.Services;

public sealed class ClientShipmentService : IShipmentService
{
    private readonly HttpClient _http;

    public ClientShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        response.EnsureSuccessStatusCode();
        var result = await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
        return result ?? throw new InvalidOperationException("Received null response from server.");
    }
}

